## Observed Chats API — Server Endpoint and Client Hook

Provide a server endpoint that returns observed chat IDs from the trace store, plus a TanStack Query hook for the client.

### Server Endpoint

In `apps/server/src/routes/relay.ts`, add inside the `if (adapterManager)` block, after the adapter events route:

```typescript
// GET /adapters/:id/chats — Observed chats from trace data
router.get('/adapters/:id/chats', (_req, res) => {
  if (!traceStore) return res.status(404).json({ error: 'Tracing not available' });
  const { id } = _req.params;
  const limitParam = parseInt(_req.query.limit as string);
  const limit = Number.isNaN(limitParam) ? 100 : Math.min(Math.max(limitParam, 1), 500);
  const chats = traceStore.getObservedChats(id, limit);
  return res.json({ chats });
});
```

### TraceStore Method

In `apps/server/src/services/relay/trace-store.ts`, add a `getObservedChats` method to the `TraceStore` class:

```typescript
/**
 * Get observed chats for an adapter by querying trace metadata.
 *
 * Extracts unique chatId values from trace span metadata where the
 * subject matches the adapter pattern, groups by chatId, and returns
 * aggregated results sorted by most recent message.
 *
 * @param adapterId - Adapter instance ID to filter by
 * @param limit - Maximum number of chats to return (default 100)
 */
getObservedChats(adapterId: string, limit = 100): ObservedChat[] {
  // Query traces that have metadata containing the adapterId
  // The metadata JSON field contains {adapterId, chatId, channelType, displayName}
  // We use SQLite JSON functions to extract and group
  const rows = this.db
    .select({
      metadata: relayTraces.metadata,
      sentAt: relayTraces.sentAt,
    })
    .from(relayTraces)
    .where(
      sql`json_extract(${relayTraces.metadata}, '$.adapterId') = ${adapterId}`
    )
    .all();

  // Group by chatId in application code
  const chatMap = new Map<string, {
    chatId: string;
    displayName?: string;
    channelType?: string;
    lastMessageAt: string;
    messageCount: number;
  }>();

  for (const row of rows) {
    if (!row.metadata) continue;
    try {
      const meta = JSON.parse(row.metadata) as Record<string, unknown>;
      const chatId = meta.chatId as string | undefined;
      if (!chatId) continue;

      const existing = chatMap.get(chatId);
      if (existing) {
        existing.messageCount++;
        if (row.sentAt > existing.lastMessageAt) {
          existing.lastMessageAt = row.sentAt;
        }
      } else {
        chatMap.set(chatId, {
          chatId,
          displayName: meta.displayName as string | undefined,
          channelType: meta.channelType as string | undefined,
          lastMessageAt: row.sentAt,
          messageCount: 1,
        });
      }
    } catch {
      // Skip malformed metadata
    }
  }

  // Sort by lastMessageAt descending and limit
  return Array.from(chatMap.values())
    .sort((a, b) => b.lastMessageAt.localeCompare(a.lastMessageAt))
    .slice(0, limit);
}
```

Import `ObservedChat` type from `@dorkos/shared/relay-schemas` (or define the return type inline if the module re-export isn't set up yet).

### Client Hook

Create `apps/client/src/layers/entities/relay/model/use-observed-chats.ts`:

```typescript
import { useQuery } from '@tanstack/react-query';
import { useTransport } from '@/layers/shared/model';
import type { ObservedChat } from '@dorkos/shared/relay-schemas';

/**
 * Fetch observed chats for an adapter instance.
 *
 * Used by the BindingDialog chatId picker to show real chats
 * the adapter has seen in trace data.
 *
 * @param adapterId - Adapter instance ID, or undefined to skip the query
 */
export function useObservedChats(adapterId: string | undefined) {
  const transport = useTransport();
  return useQuery<ObservedChat[]>({
    queryKey: ['relay', 'observed-chats', adapterId],
    queryFn: () => transport.getObservedChats(adapterId!),
    enabled: !!adapterId,
    staleTime: 30_000,
  });
}
```

Export from `apps/client/src/layers/entities/relay/index.ts`:

```typescript
