      .send({
        adapterId: 'telegram-1',
        agentId: 'agent-1',
        projectPath: '/home/user/project',
        sessionStrategy: 'per-chat',
        label: 'Test binding',
      })
      .expect(201);

    const bindingId = createRes.body.binding.id;
