    // 2. Read
    const readRes = await request(app)
      .get(`/api/relay/bindings/${bindingId}`)
      .expect(200);
    expect(readRes.body.binding.label).toBe('Test binding');

    // 3. Update via PATCH
    const updateRes = await request(app)
      .patch(`/api/relay/bindings/${bindingId}`)
      .send({
