    // 5. Delete
    await request(app)
      .delete(`/api/relay/bindings/${bindingId}`)
      .expect(200);

    // 6. Verify gone
    await request(app)
      .get(`/api/relay/bindings/${bindingId}`)
      .expect(404);
  });

  it('clears optional fields with null values', async () => {
